3	
4	// ---------------------------------------------------------------------------
5	// PWA & Service Worker E2E tests
6	//
7	// These run against `wrangler dev`. The service worker is registered via
8	// data-init on page load. Manifest and icon files are served as static assets
9	// from the Worker.
10	// ---------------------------------------------------------------------------
11	
12	test.describe("PWA & Service Worker", () => {
13	  test.beforeAll(async ({ browser }) => {
14	    const page = await browser.newPage();
15	    try {
16	      await seedDatabase(page);
17	    } catch {
18	      // Seed may fail if user already exists — that's fine
19	    } finally {
20	      await page.close();
21	    }
22	  });
23	
24	  test("service worker registers successfully", async ({ page }) => {
25	    await page.goto("/");
26	
27	    // Wait for the page shell to load before checking SW registration
28	    await page.waitForLoadState("domcontentloaded");
29	
30	    // Check that the service worker registers and reaches activated state
31	    const swState = await page.evaluate(async () => {
32	      const registration = await navigator.serviceWorker.getRegistration("/");
33	      if (!registration) return null;
34	
35	      const sw =
36	        registration.active ||
37	        registration.installing ||
38	        registration.waiting;
39	      if (!sw) return null;
40	
41	      if (sw.state === "activated") return "activated";
42	
43	      // Wait for the SW to activate with a timeout fallback
44	      return new Promise<string>((resolve) => {
45	        const timeout = setTimeout(() => resolve(sw.state), 5000);
46	        sw.addEventListener("statechange", function handler() {
47	          if (sw.state === "activated") {
48	            clearTimeout(timeout);
49	            sw.removeEventListener("statechange", handler);
50	            resolve("activated");
51	          }
52	        });
53	      });
54	    });
55	
56	    expect(swState).toBe("activated");
57	  });
58	
59	  test("manifest has required icon entries", async ({ page }) => {
60	    const response = await page.request.get(`${BASE_URL}/manifest.json`);
61	    expect(response.status()).toBe(200);
